messages.content:
你是 marketting-planning-intent 项目的 attribute agent。
只归因当前单轮 intent-recognition 链路：request_normalization、intent_api_call、adapter_extraction、label_mapping；不要把 planning/SSE generation 的问题归入本项目。
优先使用 intent_contract_probe 定位 intent label、required slots/entities、confidence threshold、fallback policy 或 label_mapping 的当前证据差异。
只能输出 AttributeResult JSON 所需字段；证据不足时用 evidence_strength=none/weak 和 root_cause_hypothesis 表达缺口。
最终只输出 AttributeResult JSON 所需字段：expectation_attributions、suspected_locations、root_cause_hypothesis、evidence、evidence_strength。

## 输出约束：attribute 归因分析输出
你的输出必须是合法 JSON，且严格符合以下 JSON Schema：
```json
{
  "type": "object",
  "properties": {
    "expectation_attributions": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/ExpectationAttribution"
      },
      "minItems": 1
    },
    "suspected_locations": {
      "type": "array",
      "items": {}
    },
    "root_cause_hypothesis": {
      "type": "string",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "items": {}
    },
    "evidence_strength": {
      "type": "string",
      "minLength": 1
    }
  },
  "additionalProperties": false,
  "$defs": {
    "ExpectationAttribution": {
      "type": "object",
      "properties": {
        "expectation_id": {
          "type": "string",
          "minLength": 1
        },
        "fulfillment_status": {
          "type": "string",
          "minLength": 1
        },
        "suspected_locations": {
          "type": "array",
          "items": {}
        },
        "root_cause_hypothesis": {
          "type": "string",
          "minLength": 1
        },
        "evidence": {
          "type": "array",
          "items": {}
        }
      },
      "additionalProperties": false,
      "required": [
        "expectation_id",
        "fulfillment_status"
      ]
    }
  },
  "required": [
    "expectation_attributions",
    "root_cause_hypothesis"
  ]
}
```

### 强约束
- 最终回答必须只包含一个 JSON object；不要输出 Markdown，不要使用 ```json 代码块，不要在 JSON 外输出解释、前缀或后缀。
- 最终回答首字符必须是 `{`，末字符必须是 `}`。
- JSON 字符串内部如需引用用户原词，禁止直接写未转义英文双引号；请使用中文引号“”或转义为 `\"`。
- 必须包含 `required` 列表中的所有字段。
- 每个字段值必须匹配 schema 中的类型。
- 以下字段必须非空（空字符串/空数组/空对象/None 均视为不合规，会被阻断）：['expectation_attributions', 'root_cause_hypothesis']
- `additionalProperties: false`：禁止输出 schema 未定义的字段。
- 禁止把 schema 里的类型描述符（如 "string"）原样当作内容填进去——每个字段必须填入真实内容。

{
  "expectation_attributions": [
    {
      "expectation_id": "意图标签应为customer_portrait",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {"stage": "intent_api_call", "reason": "意图识别API未能将查询识别为customer_portrait，返回了other或低置信度意图。"},
        {"stage": "adapter_extraction", "reason": "适配器提取未纠正错误意图，直接传递了other。"},
        {"stage": "label_mapping", "reason": "标签映射将无有效意图的输入映射为other，未保持正确标签。"}
      ],
      "root_cause_hypothesis": "意图识别API未正确解析查询中的“客户画像”需求，导致输出other意图；适配器提取和标签映射均未修复此错误，最终意图标签与期望不符。",
      "evidence": [
        {"source": "extracted_output", "value": {"intent": "other"}},
        {"source": "intent_contract_probe", "value": {"intent_match": false, "evidence_gap": ["intent_evidence"]}},
        {"source": "runtime_checks", "value": {"raw_intent": null, "actual_intent": "other", "expected_intent": "customer_portrait"}}
      ]
    },
    {
      "expectation_id": "目标实体应为重疾险",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {"stage": "intent_api_call", "reason": "意图识别API响应中未包含target_value字段，实体抽取缺失。"},
        {"stage": "adapter_extraction", "reason": "适配器提取未生成或补全target_value实体。"}
      ],
      "root_cause_hypothesis": "意图识别API未能从查询中抽取“重疾险”实体，适配器提取也未输出该槽位，导致下游缺少关键筛选条件。",
      "evidence": [
        {"source": "extracted_output", "value": "缺少target_value字段"},
        {"source": "judge_result", "value": {"missing": [{"kind": "target_value", "expected": "重疾险", "actual": null}]}}
      ]
    },
    {
      "expectation_id": "置信度至少为0.9",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {"stage": "intent_api_call", "reason": "API返回的置信度仅0.5，远低于要求的0.9。"},
        {"stage": "adapter_extraction", "reason": "适配器提取未提升或补救置信度。"}
      ],
      "root_cause_hypothesis": "意图识别模型对查询分类不确定，给出的置信度0.5，可能因为训练数据不足或查询表述模糊，未达到业务高置信度要求。",
      "evidence": [
        {"source": "extracted_output", "value": {"confidence": 0.5}},
        {"source": "intent_contract_probe", "value": {"actual_confidence": 0.5}}
      ]
    },
    {
      "expectation_id": "不应错误触发fallback意图",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {"stage": "adapter_extraction", "reason": "提取出的意图为other，即触发了fallback。"},
        {"stage": "label_mapping", "reason": "映射逻辑将无效意图归类为other，导致fallback。"}
      ],
      "root_cause_hypothesis": "由于上游意图识别错误，导致最终意图落入other类别，错误触发了fallback机制，将明确的业务查询误判为非业务意图。",
      "evidence": [
        {"source": "extracted_output", "value": {"intent": "other"}},
        {"source": "judge_result", "value": {"wrong": [{"kind": "intent_label", "actual": "other", "expected": "customer_portrait"}]}}
      ]
    },
    {
      "expectation_id": "intent_contract",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {"stage": "intent_api_call", "reason": "API未满足reference contract的意图和置信度要求。"},
        {"stage": "adapter_extraction", "reason": "提取结果与contract严重偏离。"},
        {"stage": "label_mapping", "reason": "映射进一步固化了错误结果。"}
      ],
      "root_cause_hypothesis": "整个单轮意图识别链路未能满足reference contract：意图识别为other而非customer_portrait，置信度0.5远低于0.95，关键实体缺失，整体判定为incorrect。根源在于API识别能力不足和映射容错性差。",
      "evidence": [
        {"source": "reference_contract", "value": {"intent": "customer_portrait", "confidence": 0.95, "target_value": "重疾险"}},
        {"source": "actual_output", "value": {"intent": "other", "confidence": 0.5, "target_value": null}},
        {"source": "runtime_checks", "value": {"raw_intent": null, "actual_mapping": "other", "root_cause": "label_mapping"}}
      ]
    }
  ],
  "suspected_locations": [
    {
      "stage": "intent_api_call",
      "reason": "API返回了错误的意图other和低置信度0.5，且未提供target_value实体，是链路的原始错误源。"
    },
    {
      "stage": "adapter_extraction",
      "reason": "适配器未对API结果进行校验或纠正，直接传递了错误意图和缺失实体。"
    },
    {
      "stage": "label_mapping",
      "reason": "映射阶段将raw_intent=None映射为other，未识别出无有效意图并向上游报告，加剧了错误传播。"
    }
  ],
  "root_cause_hypothesis": "根本原因在于意图识别API对中文保险领域查询“帮我看看上季度买了重疾险的客户都是啥样的？”识别失败，输出other意图且置信度仅0.5，未抽取关键实体；下游适配器提取和标签映射均无纠错机制，导致最终结果与期望严重偏离。",
  "evidence": [
    {
      "source": "extracted_output",
      "content": {"intent": "other", "confidence": 0.5, "subIntent": "其他意图"}
    },
    {
      "source": "runtime_checks",
      "content": {
        "raw_intent": null,
        "actual_intent": "other",
        "expected_intent": "customer_portrait",
        "root_cause": {"category": "label_mapping", "summary": "raw_intent=None映射得到other"}
      }
    },
    {
      "source": "intent_contract_probe",
      "content": {
        "intent_match": false,
        "actual_confidence": 0.5,
        "evidence_gap": ["intent_evidence"],
        "actual_intent": "other"
      }
    },
    {
      "source": "judge_result",
      "content": {
        "missing": [{"kind": "target_value", "expected": "重疾险"}],
        "wrong": [{"kind": "intent_label", "expected": "customer_portrait", "actual": "other"}],
        "fulfillment_assessments": "多个期望未满足"
      }
    }
  ],
  "evidence_strength": "high"
}

